using namespace session_cpp;

static Mesh build_mesh(const std::vector<std::vector<Point>>& polys) {
    std::map<std::tuple<long,long,long>, size_t> vmap;
    std::vector<Point> verts;
    std::vector<std::vector<size_t>> faces;
    for (const auto& poly : polys) {
        std::vector<size_t> face;
        for (size_t i = 0; i < poly.size(); ++i) {
            const auto& p = poly[i];
            long lx = std::lround(p[0] * 1000);
            long ly = std::lround(p[1] * 1000);
            long lz = std::lround(p[2] * 1000);
            if (i == poly.size() - 1 && !face.empty()) {
                long fx = std::lround(poly[0][0] * 1000);
                long fy = std::lround(poly[0][1] * 1000);
                long fz = std::lround(poly[0][2] * 1000);
                if (lx == fx && ly == fy && lz == fz) continue;
            }
            auto key = std::make_tuple(lx, ly, lz);
            auto it = vmap.find(key);
            size_t idx;
            if (it == vmap.end()) {
                idx = verts.size();
                vmap[key] = idx;
                verts.push_back(p);
            } else {
                idx = it->second;
            }
            if (!face.empty() && face.back() == idx) continue;
            face.push_back(idx);
        }
        if (face.size() >= 3) faces.push_back(face);
    }
    return Mesh::from_vertices_and_faces(verts, faces);
}

